import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import '../../styles/header.css';
import logo from '../../assets/logo.png';

const Header: React.FC = () => {
    const navigate = useNavigate();
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    // Navigation handlers
    const handleLogin = () => {
        navigate('/login');
        setIsMobileMenuOpen(false);
    };

    const handleSignUp = () => {
        navigate('/register');
        setIsMobileMenuOpen(false);
    };

    const handleHomeClick = () => navigate('/');

    // Toggle mobile menu
    const toggleMobileMenu = () => {
        setIsMobileMenuOpen(!isMobileMenuOpen);
    };

    // Close mobile menu when clicking a link
    const handleNavLinkClick = () => {
        setIsMobileMenuOpen(false);
    };

    // Smooth scroll for anchor links
    const handleAnchorClick = (e: React.MouseEvent<HTMLAnchorElement>, id: string) => {
        e.preventDefault();
        const element = document.getElementById(id);
        if (element) {
            element.scrollIntoView({ behavior: 'smooth' });
        }
        setIsMobileMenuOpen(false);
    };

    return (
        <>
            {/* Overlay for mobile menu */}
            <div 
                className={`mobile-overlay ${isMobileMenuOpen ? 'active' : ''}`}
                onClick={() => setIsMobileMenuOpen(false)}
            />

            <header className="header">
                <div className="container">
                    <nav className="navbar">
                        {/* Logo */}
                        <div className="logo" onClick={handleHomeClick} style={{ cursor: 'pointer' }}>
                            <img src={logo} alt="Channel4Me Logo" />
                            <span>Channel4Me</span>
                        </div>

                        {/* Navigation Menu */}
                        <ul className={`nav-menu ${isMobileMenuOpen ? 'mobile-open' : ''}`}>
                            <li>
                                <Link 
                                    to="/" 
                                    className="nav-link" 
                                    onClick={handleNavLinkClick}
                                >
                                    Home
                                </Link>
                            </li>
                            <li>
                                <a 
                                    href="#features" 
                                    className="nav-link" 
                                    onClick={(e) => handleAnchorClick(e, 'features')}
                                >
                                    Features
                                </a>
                            </li>
                            <li>
                                <a 
                                    href="#doctors" 
                                    className="nav-link" 
                                    onClick={(e) => handleAnchorClick(e, 'doctors')}
                                >
                                    Doctors
                                </a>
                            </li>
                            <li>
                                <a 
                                    href="#specialties" 
                                    className="nav-link" 
                                    onClick={(e) => handleAnchorClick(e, 'specialties')}
                                >
                                    Specialties
                                </a>
                            </li>
                            <li>
                                <a 
                                    href="#about" 
                                    className="nav-link" 
                                    onClick={(e) => handleAnchorClick(e, 'about')}
                                >
                                    About
                                </a>
                            </li>
                        </ul>

                        {/* Desktop Action Buttons */}
                        <div className="nav-buttons">
                            <button className="btn btn-login" onClick={handleLogin}>
                                Log In
                            </button>
                            <button className="btn btn-primary" onClick={handleSignUp}>
                                Sign Up Free
                            </button>
                        </div>

                        {/* Mobile Menu Toggle */}
                        <button 
                            className={`mobile-menu-btn ${isMobileMenuOpen ? 'active' : ''}`}
                            onClick={toggleMobileMenu}
                            aria-label="Toggle menu"
                        >
                            <span></span>
                            <span></span>
                            <span></span>
                        </button>
                    </nav>
                </div>

                {/* Mobile Action Buttons (shown only in mobile menu) */}
                <div className={`nav-buttons-mobile ${isMobileMenuOpen ? 'active' : ''}`}>
                    <button className="btn btn-login" onClick={handleLogin}>
                        Log In
                    </button>
                    <button className="btn btn-primary" onClick={handleSignUp}>
                        Sign Up Free
                    </button>
                </div>
            </header>
        </>
    );
};

export default Header;
